// =============================================================================
// logos.js — Organisation emblems.
//
// The Omega-1 and Ethics Committee crests, embedded as base64 PNG data URLs so
// they are fully self-contained: they render in the web UI and, crucially, in
// downloaded/printed export documents where a relative asset path would not
// resolve. Sourced from artwork supplied by the site owner; white background
// removed so the ink sits cleanly on any surface.
// =============================================================================

export const OMEGA_LOGO = 'data:image/png;base64,';
export const ETHICS_LOGO = 'data:image/png;base64,';

// Return the emblem data URL for an organisation, or null if it has no crest.
export function orgLogo(orgKey) {
  if (orgKey === 'omega-1') return OMEGA_LOGO;
  if (orgKey === 'ethics-committee') return ETHICS_LOGO;
  return null;
}
